console.log('\n==============================================');
console.log('post install react-scanner');
try {
    const path = require('path');
    const scanner = require('react-scanner');
    const axios = require('axios');
    const scannerConfig = require('./react-scanner.config.cjs');
    const https = require('https');
    const fs = require('node:fs');

    const hostname = 'https://ds-statistic-nest.apps.yd-m6-kt22.vimpelcom.ru';
    const uriPath = {
        postStatisticOptions: '/component/create-statistic',
        needRefresh: '/component/need-refresh'
    }
    const NO_URL = 'Url не найден';
    let projectUrl = NO_URL;
    let appPJson = null;
    try {
        const httpsAgent = new https.Agent({
            rejectUnauthorized: false
        });

        try {
            projectUrl = require('node:child_process').execSync('git remote get-url origin')
                .toString().trim();
        } catch (e) {
            console.log('git url not found');
        }

        try {
            appPJson = require(path.join(process.cwd(), '../../../package.json'));
        } catch (e) {
            console.log('Не найден  package.json проекта ');
        }
        if (appPJson && projectUrl !== NO_URL) {
            const uri = hostname + uriPath.needRefresh + `?gitUrl=${projectUrl}`
            axios.get(
                uri,
                { httpsAgent }
            ).then(async (res) => {
                if (res.data.needRefresh) {
                    await startScanner({
                        app: appPJson?.name || '',
                        appVer: appPJson?.version || '',
                        appLink: projectUrl
                    })
                }
            }).catch((error) => {
                console.log(`Не удалось установить необходимость обновления статистики`);
            });
        } else {
            console.log('Данные о проекте не найдены, отправка приостановлена');
        }

    } catch (e) {
        console.log('Ошибка при отправке статистики design-system');
    }

    async function startScanner(appInfo) {
        const httpsAgent = new https.Agent({
            rejectUnauthorized: false
        });
        const startDate = new Date();
        const output = await scanner.run(scannerConfig, './');
        const endDate = new Date();
        const postData = {
            appInfo,
            componentInfo: output,
            scannerTime: Math.floor((endDate - startDate) / 1000)
        };
        axios.post(
            hostname + uriPath.postStatisticOptions, 
            postData,
            { httpsAgent }
        ).then(res => {
            console.log(res);
        }).catch((e) => {
            console.log(`problem with post statistic request`);
        })

    }
} catch (e) {
    console.log('Ошибка сбора статистики')
}